* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #0a0e1a; color: white; display: flex; justify-content: center; padding: 40px 20px; min-height: 100vh; }
.app { width: 100%; max-width: 400px; }
h1 { font-size: 26px; font-weight: 800; text-align: center; margin-bottom: 8px; }
.subtitle { text-align: center; color: rgba(255,255,255,0.4); font-size: 13.5px; margin-bottom: 24px; }
.tabs { display: flex; gap: 6px; background: rgba(255,255,255,0.04); border-radius: 14px; padding: 5px; margin-bottom: 20px; }
.tab { flex: 1; background: transparent; border: none; color: rgba(255,255,255,0.5); padding: 10px 6px; border-radius: 10px; font-size: 12px; font-weight: 700; cursor: pointer; }
.tab.active { background: rgba(99,102,241,0.18); color: #818cf8; }
.form { display: flex; flex-direction: column; gap: 8px; margin-bottom: 20px; }
.form.hidden { display: none; }
.form label { font-size: 12.5px; font-weight: 700; color: rgba(255,255,255,0.5); margin-top: 8px; }
.form input, .form textarea { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); border-radius: 12px; padding: 14px 16px; color: white; font-size: 14px; outline: none; font-family: inherit; }
.form textarea { resize: vertical; min-height: 80px; }
.qr-preview { display: flex; justify-content: center; margin-bottom: 24px; }
.qr-grid { width: 220px; height: 220px; background: white; border-radius: 16px; padding: 14px; display: grid; grid-template-columns: repeat(21, 1fr); grid-template-rows: repeat(21, 1fr); box-shadow: 0 20px 50px rgba(99,102,241,0.15); }
.qr-cell { background: transparent; }
.qr-cell.on { background: #0a0e1a; }
.actions { display: flex; gap: 12px; margin-bottom: 28px; }
.actions button { flex: 1; background: rgba(255,255,255,0.06); border: 1px solid rgba(255,255,255,0.1); color: white; padding: 13px; border-radius: 12px; font-size: 13.5px; font-weight: 700; cursor: pointer; }
h2 { font-size: 16px; font-weight: 700; margin-bottom: 12px; }
.history { display: flex; flex-direction: column; gap: 8px; }
.history-item { background: rgba(255,255,255,0.04); border-radius: 10px; padding: 12px 16px; font-size: 13px; color: rgba(255,255,255,0.6); font-weight: 600; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; cursor: pointer; }
.history-item:hover { background: rgba(255,255,255,0.07); }

