let currentType = 'url';
let history = [];

function switchType(btn, type) {
  currentType = type;
  document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
  btn.classList.add('active');
  document.getElementById('formUrl').classList.toggle('hidden', type !== 'url');
  document.getElementById('formText').classList.toggle('hidden', type !== 'text');
  document.getElementById('formWifi').classList.toggle('hidden', type !== 'wifi');
  generate();
}

function getCurrentValue() {
  if (currentType === 'url') return document.getElementById('urlInput').value;
  if (currentType === 'text') return document.getElementById('textInput').value;
  if (currentType === 'wifi') {
    const ssid = document.getElementById('wifiSsid').value;
    const pass = document.getElementById('wifiPass').value;
    return `WIFI:S:${ssid};P:${pass};;`;
  }
  return '';
}

// Basit, deterministik bir "QR benzeri" desen üretir (gerçek QR kodlama değildir, görsel önizleme amaçlıdır)
function hashString(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = (hash << 5) - hash + str.charCodeAt(i);
    hash |= 0;
  }
  return hash;
}

function generate() {
  const value = getCurrentValue();
  const grid = document.getElementById('qrGrid');
  grid.innerHTML = '';
  const size = 21;
  const seed = Math.abs(hashString(value || 'playground'));

  for (let row = 0; row < size; row++) {
    for (let col = 0; col < size; col++) {
      const cell = document.createElement('div');
      cell.className = 'qr-cell';

      // Köşe konumlama kareleri (QR koda benzer görünüm için)
      const isCorner =
        (row < 7 && col < 7) ||
        (row < 7 && col >= size - 7) ||
        (row >= size - 7 && col < 7);

      let on;
      if (isCorner) {
        const r = row < 7 ? row : row - (size - 7);
        const c = col < 7 ? col : col - (size - 7);
        on = (r === 0 || r === 6 || c === 0 || c === 6 || (r >= 2 && r <= 4 && c >= 2 && c <= 4));
      } else {
        const n = (seed + row * 31 + col * 17 + row * col) % 100;
        on = n < 48;
      }

      if (on) cell.classList.add('on');
      grid.appendChild(cell);
    }
  }

  addHistory(value);
}

function addHistory(value) {
  if (!value || history[0] === value) return;
  history.unshift(value);
  if (history.length > 5) history.pop();
  const container = document.getElementById('history');
  container.innerHTML = '';
  history.forEach(v => {
    const div = document.createElement('div');
    div.className = 'history-item';
    div.textContent = v;
    container.appendChild(div);
  });
}

